74	func ResolveAttemptBackend(rcfg config.ResolvedConfig) (AttemptBackend, error) {
75		name := strings.ToLower(strings.TrimSpace(rcfg.AttemptBackend()))
76		if name == "" {
77			name = AttemptBackendWorktree
78		}
79		switch name {
80		case AttemptBackendWorktree, "linked-worktree":
81			return WorktreeAttemptBackend{}, nil
82		case AttemptBackendLocalClone, "clone":
83			return LocalCloneAttemptBackend{CloneMode: dockerCloneMode(rcfg.ExecutionsDockerConfig())}, nil
84		case AttemptBackendDockerClone, "docker":
85			return DockerCloneAttemptBackend{Docker: rcfg.ExecutionsDockerConfig()}, nil
86		default:
87			return nil, fmt.Errorf("unknown attempt backend %q (valid: %s, %s, %s)",
88				name, AttemptBackendWorktree, AttemptBackendLocalClone, AttemptBackendDockerClone)
89		}
90	}
