206	func (b DockerCloneAttemptBackend) Prepare(ctx context.Context, req AttemptBackendPrepareRequest) (*AttemptWorkspace, error) {
207		ws, err := (LocalCloneAttemptBackend{CloneMode: dockerCloneMode(b.Docker)}).Prepare(ctx, req)
208		if err != nil {
209			return nil, err
210		}
211		ws.Backend = AttemptBackendDockerClone
212		ws.KeepOnError = b.Docker != nil && b.Docker.KeepOnError
213		ws.DockerRun = executeBeadDockerRunPath(req.ProjectRoot, req.BeadID, req.AttemptID)
214		ws.DockerHome = filepath.Join(ws.DockerRun, "home")
215		if err := prepareDockerAttemptRuntime(ws.DockerRun); err != nil {
216			_ = os.RemoveAll(ws.WorkDir)
217			return nil, err
218		}
219		if err := prepareDockerAttemptHome(ws.DockerHome); err != nil {
220			_ = os.RemoveAll(ws.WorkDir)
221			_ = os.RemoveAll(ws.DockerRun)
222			return nil, err
223		}
224		if !dockerSharedGoCacheDisabled(b.Docker) {
225			shared := dockerSharedGoCachePath(req.ProjectRoot)
226			if err := os.MkdirAll(shared, 0o700); err == nil {
227				ws.DockerSharedGoCache = shared
228			}
229		}
230		return ws, nil
231	}
