233	func (b DockerCloneAttemptBackend) Run(ctx context.Context, req AttemptBackendRunRequest) (*Result, error) {
234		cfg := b.Docker
235		image := ""
236		if cfg != nil {
237			image = strings.TrimSpace(cfg.Image)
238		}
239		if image == "" {
240			return nil, fmt.Errorf("docker-clone attempt backend requires executions.docker.image")
241		}
242		if req.Workspace == nil || req.Workspace.WorkDir == "" {
243			return nil, fmt.Errorf("docker-clone attempt backend missing workspace")
244		}
245		image, err := resolveDockerAttemptImage(ctx, cfg, req.ProjectRoot, image)
246		if err != nil {
247			return nil, err
248		}
249		exe, err := os.Executable()
250		if err != nil {
251			return nil, fmt.Errorf("resolving ddx executable for docker backend: %w", err)
252		}
253		promptPath, err := containerPath(req.Workspace.WorkDir, req.Runtime.PromptFile)
254		if err != nil {
255			return nil, err
256		}
257	
258		containerName := dockerContainerName(req.Workspace)
259		args := dockerRunArgs(cfg, req.Workspace, exe, image, dockerToolMounts())
260		runArgs := []string{
261			"ddx", "run",
262			"--project", "/work",
263			"--prompt", promptPath,
264			"--output", "json-result",
265			"--permissions", firstNonEmpty(req.Runtime.PermissionsOverride, req.Config.Permissions()),
266		}
267		if h := strings.TrimSpace(req.Config.Harness()); h != "" {
268			runArgs = append(runArgs, "--harness", h)
269		}
270		if p := strings.TrimSpace(req.Config.Provider()); p != "" {
271			runArgs = append(runArgs, "--provider", p)
272		}
273		if m := strings.TrimSpace(req.Config.Model()); m != "" {
274			runArgs = append(runArgs, "--model", m)
275		}
276		if p := strings.TrimSpace(req.Config.Profile()); p != "" {
277			runArgs = append(runArgs, "--profile", p)
278		}
279		if e := strings.TrimSpace(req.Config.Effort()); e != "" {
280			runArgs = append(runArgs, "--effort", e)
281		}
282		if min := req.Config.MinPower(); min > 0 {
283			runArgs = append(runArgs, "--min-power", strconv.Itoa(min))
284		}
285		if max := req.Config.MaxPower(); max > 0 {
286			runArgs = append(runArgs, "--max-power", strconv.Itoa(max))
287		}
288		if timeout := req.Config.Timeout(); timeout > 0 {
289			runArgs = append(runArgs, "--timeout", timeout.String())
290		}
291		args = append(args, runArgs...)
292	
293		cmd := dockerAttemptCommand(ctx, args...)
294		cmd.Dir = req.Workspace.ProjectRoot
295		var stdout, stderr bytes.Buffer
296		cmd.Stdout = &stdout
297		cmd.Stderr = &stderr
298		defer func() {
299			_ = dockerRemoveContainer(context.Background(), containerName)
300		}()
301		err = cmd.Run()
302	
303		result, parseErr := parseDockerRunResult(stdout.Bytes())
304		if parseErr == nil {
305			if strings.TrimSpace(stderr.String()) != "" && result.Stderr == "" {
306				result.Stderr = strings.TrimSpace(stderr.String())
307			}
308			return result, nil
309		}
310		if err != nil {
311			return nil, fmt.Errorf("docker-clone attempt failed: %s: %w", strings.TrimSpace(stderr.String()), err)
312		}
313		return nil, parseErr
314	}
