357	func localCloneArgs(mode, projectRoot, clonePath string) []string {
358		cloneArgs := []string{"clone", "--no-checkout"}
359		switch strings.ToLower(strings.TrimSpace(mode)) {
360		case "copy", "no-hardlinks", "no-hardlink":
361			cloneArgs = append(cloneArgs, "--no-hardlinks")
362		default:
363			cloneArgs = append(cloneArgs, "--local")
364		}
365		return append(cloneArgs, projectRoot, clonePath)
366	}
