533	func dockerProjectDockerfile(projectRoot string, cfg *config.ExecutionsDockerConfig) (string, bool, error) {
534		configured := ""
535		if cfg != nil {
536			configured = strings.TrimSpace(cfg.ProjectDockerfile)
537		}
538		if configured == "" {
539			defaultPath := ddxroot.InTree(projectRoot, "attempt-runner.Dockerfile")
540			info, err := os.Stat(defaultPath)
541			if err != nil {
542				if os.IsNotExist(err) {
543					return "", false, nil
544				}
545				return "", false, err
546			}
547			if info.IsDir() {
548				return "", false, fmt.Errorf("docker project dockerfile is a directory: %s", defaultPath)
549			}
550			return defaultPath, true, nil
551		}
552		path, err := projectBoundPath(projectRoot, configured)
553		if err != nil {
554			return "", false, fmt.Errorf("docker project dockerfile: %w", err)
555		}
556		info, err := os.Stat(path)
557		if err != nil {
558			return "", false, fmt.Errorf("docker project dockerfile %s: %w", path, err)
559		}
560		if info.IsDir() {
561			return "", false, fmt.Errorf("docker project dockerfile is a directory: %s", path)
