782	func copyDockerAuthFileIfExists(src, dst string) error {
783		info, err := os.Stat(src)
784		if err != nil {
785			if os.IsNotExist(err) {
786				return nil
787			}
788			return fmt.Errorf("stat docker auth file %s: %w", src, err)
789		}
790		if info.IsDir() {
791			return nil
792		}
793		raw, err := os.ReadFile(src)
794		if err != nil {
795			return fmt.Errorf("read docker auth file %s: %w", src, err)
796		}
797		if err := os.MkdirAll(filepath.Dir(dst), 0o700); err != nil {
798			return fmt.Errorf("create docker auth dir %s: %w", filepath.Dir(dst), err)
799		}
800		if err := os.WriteFile(dst, raw, 0o600); err != nil {
801			return fmt.Errorf("write docker auth file %s: %w", dst, err)
802		}
803		return nil
804	}
