854	func sanitizeDockerName(s string) string {
855		var b strings.Builder
856		for _, r := range s {
857			switch {
858			case r >= 'a' && r <= 'z', r >= 'A' && r <= 'Z', r >= '0' && r <= '9', r == '-', r == '_', r == '.':
859				b.WriteRune(r)
860			default:
861				b.WriteByte('-')
862			}
863		}
864		out := strings.Trim(b.String(), "-_.")
865		if out == "" {
866			return "attempt"
867		}
868		if len(out) > 80 {
869			return out[:80]
870		}
871		return out
872	}
